#include<bits/stdc++.h>
using namespace std;
int n,m,a[1000010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    multiset<int> s;
    for(int i=1;i<=m+1;i++)
    {
        s.insert(a[i]);
    }
    int ans=1e9;
    for(int i=1;i+m<=n;i++)
    {
        ans=min(ans,(*s.rbegin()));
        s.insert(a[i+m+1]);
        s.erase(s.lower_bound(a[i]));
    }
    printf("%d",ans);
    return 0;
}
